#!/usr/bin/env bash
# mistral-iq-ladder-watcher.sh
# ---------------------------------------------------------------------------
# Auto-submit the Mistral-7B IQ-ladder encode the moment the Codestral-22B
# ladder (build 7c829a70) SUCCEEDS — respecting the campaign's one-encode-at-
# a-time rule. Fully self-contained, deterministic, and IDEMPOTENT: it can be
# fired hourly forever and will submit Mistral AT MOST ONCE.
#
# Exit codes (read by the scheduling wrapper to decide whether to self-disable):
#   0  = non-terminal: Codestral still running, or a ladder encode is ongoing.
#        Keep watching — re-check next tick.
#   10 = TERMINAL: Mistral submitted just now. Stop the schedule.
#   11 = TERMINAL: Mistral was already submitted on a prior tick. Stop the schedule.
#   20 = TERMINAL: Codestral did NOT succeed (FAILURE/CANCELLED/TIMEOUT/…).
#        Mistral NOT submitted. Stop the schedule and surface for a human.
#
# Design notes:
#   * The .submitted marker is the real double-submit guard (survives crashes).
#   * A single-flight lockdir prevents overlapping hourly runs from racing.
#   * Gate = Codestral SUCCESS *and* no ongoing build carries a `_HF_SOURCE`
#     substitution (i.e. no IQ-ladder encode is in flight) — matches the
#     "one encode at a time" pipeline convention. The small IQ2_M ppl-anchor
#     builds (only `_R2_PROXY_URL`) do NOT block, by design.
# ---------------------------------------------------------------------------
set -u

# --- cron-safe environment -------------------------------------------------
# cron runs with a minimal PATH and may not export HOME the way an interactive
# shell does. Make this script self-sufficient so it works identically whether
# fired by cron, a login shell, or by hand.
#   * PATH: prepend the Homebrew bin (holds the `gcloud` symlink) and the
#     Google Cloud SDK bin dir so `gcloud` always resolves.
#   * CLOUDSDK_CONFIG: pin the gcloud config dir (auth + active config) so a
#     cron-provided HOME cannot point gcloud at an unconfigured/anonymous state.
#   * CLOUDSDK_CORE_PROJECT: pin the project as a belt-and-suspenders default.
export PATH="/opt/homebrew/bin:/opt/homebrew/share/google-cloud-sdk/bin:/usr/bin:/bin:/usr/sbin:/sbin:${PATH:-}"
export CLOUDSDK_CONFIG="/Users/buley/.config/gcloud"
export CLOUDSDK_CORE_PROJECT="neutral-418500"

REPO="/Users/buley/Documents/Code/monorepo"
PROJECT="neutral-418500"
CODESTRAL_BUILD="7c829a70-75df-40c4-9004-153c6bbd5d95"
DI="$REPO/open-source/gnosis/distributed-inference"
LOG="$DI/IQ_ROLLOUT_LOG.md"
STATE="$DI/scripts/.mistral-watcher"     # state dir (markers + lock)
DONE="$STATE/submitted"                   # idempotency guard (holds new build id)
BLOCKED="$STATE/blocked"                  # codestral-failed surface
LOCK="$STATE/lock.d"

mkdir -p "$STATE" 2>/dev/null

log() { echo "[mistral-watcher $(date -u +%Y-%m-%dT%H:%M:%SZ)] $*"; }

# --- terminal-state short-circuits (idempotency) --------------------------
if [ -f "$DONE" ]; then
  log "STATUS=ALREADY_SUBMITTED build=$(cat "$DONE" 2>/dev/null)"
  exit 11
fi
if [ -f "$BLOCKED" ]; then
  log "STATUS=BLOCKED $(cat "$BLOCKED" 2>/dev/null) — not submitting; human decision needed"
  exit 20
fi

# --- single-flight lock ---------------------------------------------------
if ! mkdir "$LOCK" 2>/dev/null; then
  log "STATUS=LOCKED another run holds the lock; skipping this tick"
  exit 0
fi
trap 'rmdir "$LOCK" 2>/dev/null' EXIT

# --- 1. Codestral status --------------------------------------------------
CS=$(timeout 90 gcloud builds describe "$CODESTRAL_BUILD" \
        --project "$PROJECT" --format='value(status)' </dev/null 2>/dev/null)
log "codestral($CODESTRAL_BUILD) status=${CS:-<none>}"

case "$CS" in
  SUCCESS) ;;  # fall through to submit gate
  FAILURE|INTERNAL_ERROR|TIMEOUT|CANCELLED|EXPIRED)
    echo "codestral=$CS at $(date -u +%Y-%m-%dT%H:%M:%SZ)" > "$BLOCKED"
    log "STATUS=BLOCKED codestral=$CS — Mistral NOT submitted (human decision)"
    exit 20 ;;
  WORKING|QUEUED|PENDING|"")
    log "STATUS=WAITING codestral=${CS:-unknown} — re-check next tick"
    exit 0 ;;
  *)
    log "STATUS=WAITING codestral=unknown('$CS') — re-check next tick"
    exit 0 ;;
esac

# --- 2. one-encode-at-a-time gate -----------------------------------------
# Any ongoing build carrying a `_HF_SOURCE` substitution == an IQ-ladder
# encode is in flight. Defer until it clears.
ONGOING=$(timeout 90 gcloud builds list --project "$PROJECT" --ongoing \
            --format='value(id,substitutions._HF_SOURCE)' </dev/null 2>/dev/null)
# A build with an IQ-ladder encode running emits `<uuid>\t<org>/<repo>` (the
# _HF_SOURCE value contains a '/'). Build IDs are UUIDs (no '/'), and anchor
# builds carry only _R2_PROXY_URL (empty _HF_SOURCE → no '/'), so a line
# containing '/' means a ladder encode is in flight → defer.
if printf '%s\n' "$ONGOING" | grep -qE '[[:alnum:]_.-]+/[[:alnum:]_.-]+'; then
  log "STATUS=DEFER a ladder encode is ongoing:"
  printf '%s\n' "$ONGOING" | sed 's/^/    /'
  exit 0
fi

# --- 3. submit Mistral IQ-ladder encode (async) ---------------------------
log "codestral SUCCESS + no ladder encode ongoing → submitting Mistral IQ-ladder"
cd "$REPO" || { log "STATUS=ERROR cannot cd $REPO"; exit 0; }

# Pre-submit marker: if we die between here and writing $DONE, the next tick
# sees this and refuses to re-submit (surfaces instead) — belt & suspenders.
echo "submitting at $(date -u +%Y-%m-%dT%H:%M:%SZ)" > "$STATE/inflight"

# --async returns right after CreateBuild, but gcloud still uploads the full
# source tarball (~1.9 GiB — the earlier "50MB" .gcloudignore assumption was
# wrong) to the staging bucket BEFORE returning. Staging is slow, so the CLI
# cap must be generous or the upload gets killed mid-flight and Mistral never
# submits. 3600s (matches the hourly tick; single-flight lock covers overlap).
# The Cloud Build run itself is bounded by the yaml's global timeout: 57600s.
OUT=$(timeout 3600 gcloud builds submit \
        --config=cloudbuild-iq-ladder.yaml \
        --substitutions=_MODEL_ID=mistral-7b,_HF_SOURCE=mistralai/Mistral-7B-Instruct-v0.3,_BASELINE_GCS= \
        --project="$PROJECT" --async --quiet . </dev/null 2>&1)
RC=$?
log "gcloud builds submit rc=$RC"
printf '%s\n' "$OUT" | sed 's/^/    /'

NEWID=$(printf '%s\n' "$OUT" | grep -oE '[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}' | head -1)

if [ "$RC" -eq 0 ] && [ -n "$NEWID" ]; then
  echo "$NEWID  (submitted $(date -u +%Y-%m-%dT%H:%M:%SZ))" > "$DONE"
  rm -f "$STATE/inflight" 2>/dev/null
  # record in the campaign log
  {
    echo ""
    echo "### $(date -u +%Y-%m-%d) — Mistral IQ-ladder AUTO-SUBMITTED by watcher"
    echo "- Codestral ladder ($CODESTRAL_BUILD) = SUCCESS → mistral-watcher fired."
    echo "- mistral-7b IQ-ladder encode submitted (async):"
    echo "  build \`$NEWID\`  (_HF_SOURCE=mistralai/Mistral-7B-Instruct-v0.3,"
    echo "  _MODEL_ID=mistral-7b, empty _BASELINE_GCS → self-quant Q4_K_M ref,"
    echo "  default rungs IQ3_M,IQ3_XXS,IQ2_S,IQ2_XS)."
    echo "  Console: https://console.cloud.google.com/cloud-build/builds/$NEWID?project=366749842679"
    echo "- Watcher self-disables (idempotent; .submitted marker set)."
  } >> "$LOG" 2>/dev/null
  log "STATUS=SUBMITTED build=$NEWID"
  exit 10
else
  # Submit did not clearly succeed. Do NOT set $DONE. Leave $inflight so a
  # human investigates rather than the next tick blindly re-submitting.
  log "STATUS=SUBMIT_UNCERTAIN rc=$RC newid='${NEWID:-none}' — leaving inflight marker; NOT retrying automatically"
  # Non-terminal exit so the wrapper keeps the schedule, but the inflight
  # marker means a human should check before the next submit path runs.
  # Guard: if inflight exists on a later run and no $DONE, the wrapper prompt
  # is told to surface, not resubmit.
  exit 0
fi
